import{_ as a,a as d,b as e,c as n}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as s,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"WebDAV チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/webdav.md","filePath":"ja-JP/upload/webdav.md","lastUpdated":1781962217000}'),i={name:"ja-JP/upload/webdav.md"};function p(c,t,h,b,m,u){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="webdav-チャンネルの追加" tabindex="-1">WebDAV チャンネルの追加 <a class="header-anchor" href="#webdav-チャンネルの追加" aria-label="Permalink to &quot;WebDAV チャンネルの追加&quot;">​</a></h1><p>WebDAV チャンネルは、NAS、クラウドドライブ、WebDAV 対応ストレージへファイルを保存するための設定です。</p><h2 id="向いているケース" tabindex="-1">向いているケース <a class="header-anchor" href="#向いているケース" aria-label="Permalink to &quot;向いているケース&quot;">​</a></h2><ul><li>NAS やオンラインストレージが WebDAV URL を提供している。</li><li>アップロードした画像を自分の WebDAV ディレクトリへ保存したい。</li><li>認証情報を D1 の <code>upload_channels</code> に保存し、フロントエンドへ長期露出させたくない。</li></ul><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>例：<code>https://nas.example.com/dav</code></td></tr><tr><td>ユーザー名</td><td>WebDAV ログイン用</td></tr><tr><td>パスワード</td><td>WebDAV ログイン用。可能ならアプリパスワード</td></tr><tr><td>認証方式</td><td>通常は <code>Basic</code>。必要に応じて <code>Digest</code></td></tr><tr><td>保存ディレクトリ</td><td>任意。初期値は <code>imgbed</code></td></tr></tbody></table><h2 id="アプリパスワードを使う" tabindex="-1">アプリパスワードを使う <a class="header-anchor" href="#アプリパスワードを使う" aria-label="Permalink to &quot;アプリパスワードを使う&quot;">​</a></h2><p>サービスがアプリパスワードに対応している場合は、通常のアカウントパスワードではなくアプリパスワードを使うのがおすすめです。</p><p><img src="'+a+'" alt="アプリパスワード作成" loading="lazy"></p><p>作成後に表示されるパスワードは、一度しか表示されないことがあります。</p><p><img src="'+d+'" alt="アプリパスワード保存" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>WebDAV</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>NAS</code>、<code>Koofr</code></td></tr><tr><td>Endpoint</td><td><code>https://</code> を含む WebDAV URL</td></tr><tr><td>ユーザー名</td><td>WebDAV アカウント</td></tr><tr><td>パスワード</td><td>パスワードまたはアプリパスワード</td></tr><tr><td>認証方式</td><td>まずは <code>Basic</code></td></tr><tr><td>保存ディレクトリ</td><td>任意。通常は <code>imgbed</code></td></tr></tbody></table><p><img src="'+e+'" alt="WebDAV 設定" loading="lazy"></p><h2 id="大きなファイルの扱い" tabindex="-1">大きなファイルの扱い <a class="header-anchor" href="#大きなファイルの扱い" aria-label="Permalink to &quot;大きなファイルの扱い&quot;">​</a></h2><p>WebDAV チャンネルでは、大きなファイルをセッション式の分割アップロードで扱います。</p><table tabindex="0"><thead><tr><th>ファイルサイズ</th><th>アップロード方式</th><th>リモート側の保存形態</th></tr></thead><tbody><tr><td>64 MiB 以下</td><td>通常アップロード</td><td>1 つの完全なファイル</td></tr><tr><td>64 MiB 超</td><td>分割アップロード</td><td>分割ディレクトリ内の複数 chunk</td></tr></tbody></table><p>WebDAV サーバー側で <code>partial update</code> やオフセット書き込みに対応している必要はありません。ImgBed は分割一覧を記録し、読み取り時に順番に結合して返します。</p><p>ファイル URL は変わらず、利用者は通常どおり <code>/file/...</code> のリンクでアクセスします。</p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>確認項目</th><th>正常な状態</th></tr></thead><tbody><tr><td>チャンネルカード</td><td>保存後に表示される</td></tr><tr><td>小さなファイル</td><td>WebDAV ディレクトリにファイルが作成される</td></tr><tr><td>大きなファイル</td><td>分割ディレクトリと chunk が作成される</td></tr><tr><td>容量確認</td><td>サーバーが対応していれば使用量が表示される</td></tr></tbody></table><p><img src="'+n+`" alt="容量確認" loading="lazy"></p><p>容量確認が失敗しても、小さなファイルのアップロードが成功する場合は、サービス側が容量情報を返していないだけの可能性があります。</p><h2 id="クイック手順" tabindex="-1">クイック手順 <a class="header-anchor" href="#クイック手順" aria-label="Permalink to &quot;クイック手順&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV Endpoint、ユーザー名、パスワードを用意</span></span>
<span class="line"><span>-&gt; アップロード設定を開く</span></span>
<span class="line"><span>-&gt; チャンネル追加</span></span>
<span class="line"><span>-&gt; WebDAV を選択</span></span>
<span class="line"><span>-&gt; Endpoint / ユーザー名 / パスワードを入力</span></span>
<span class="line"><span>-&gt; 認証方式はまず Basic</span></span>
<span class="line"><span>-&gt; 保存</span></span>
<span class="line"><span>-&gt; 容量確認</span></span>
<span class="line"><span>-&gt; テストファイルをアップロード</span></span></code></pre></div>`,26)])])}const D=s(i,[["render",p]]);export{A as __pageData,D as default};
